import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { useJsxCardDialogBoardCardChange, useJsxCardDialogBoardLoadMore } from "./useCardChange";
import type { KanbanCardData } from "./types";

/**
 * JSX Card Dialog
 * cardClickAction.renderDialog — typed JSX
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 */
export default function JsxCardDialogBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const handleCardChange = useJsxCardDialogBoardCardChange();
  const handleLoadMore = useJsxCardDialogBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={boardConfig}
        cards={cards}
        onCardsChange={setCards}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

import { Sparkles } from "lucide-react";
import type { CardDialogRenderer } from "../../components/kanban/types";

/**
 * Typed JSX renderer for the card-detail dialog. Wired onto
 * `boardConfig.cardClickAction.renderDialog`.
 *
 * Resolution order at render time:
 *   cardClickAction.renderDialog → cardClickAction.dialogTemplate → default field-grid
 */
export const renderCardDialog: CardDialogRenderer = ({ card, close }) => (
  <div className="space-y-3">
    <div className="flex items-center gap-2">
      <Sparkles className="h-4 w-4 text-primary" />
      <div className="text-base font-semibold">{card.title}</div>
    </div>
    {card.description && (
      <p className="text-sm text-muted-foreground">{card.description}</p>
    )}
    <div className="grid grid-cols-2 gap-2 text-xs">
      {card.assignee && (
        <div className="rounded border border-border bg-muted/30 p-2">
          <div className="text-[10px] uppercase text-muted-foreground">Assignee</div>
          <div className="font-medium">@{card.assignee}</div>
        </div>
      )}
      {card.priority && (
        <div className="rounded border border-border bg-muted/30 p-2">
          <div className="text-[10px] uppercase text-muted-foreground">Priority</div>
          <div className="font-medium capitalize">{card.priority}</div>
        </div>
      )}
    </div>
    <div className="flex justify-end">
      <button
        type="button"
        onClick={close}
        className="text-xs px-3 py-1.5 rounded-md border border-border hover:bg-muted"
      >
        Close
      </button>
    </div>
  </div>
);

import type { KanbanBuilderConfig } from "./types";
import { renderCardDialog } from "./renderers";

/**
 * Static configuration.
 *
 * Resolution order at render time:
 *   card.render   ->   config.renderCard   ->   built-in <KanbanCard />
 */
export const boardConfig: KanbanBuilderConfig = {
  "title": "JSX Card Dialog",
  "subtitle": "cardClickAction.renderDialog — typed JSX",
  "layout": "board",
  "columns": [
    {
      "id": "todo",
      "title": "To Do",
      "color": "amber"
    },
    {
      "id": "doing",
      "title": "Doing",
      "color": "blue"
    },
    {
      "id": "done",
      "title": "Done",
      "color": "emerald"
    }
  ],
  "visibleFields": [
    "priority",
    "assignee"
  ],
  "enableDnd": true,
  "enableAddCard": true,
  "enableWipLimits": false,
  "showColumnTotals": true,
  "compactCards": false,
  "cardClickAction": {}
};

/**
 * Attach the typed JSX dialog renderer onto cardClickAction.
 *
 * Resolution order at render time (built into the engine):
 *   cardClickAction.renderDialog → cardClickAction.dialogTemplate → default field-grid
 */
boardConfig.cardClickAction = {
  ...(boardConfig.cardClickAction ?? {}),
  renderDialog: renderCardDialog,
};

import type { KanbanCardData } from "./types";

/** Initial card data. Swap with your own backend fetch when wiring up production. */
export const initialCards: KanbanCardData[] = [
  {
    "id": "j1",
    "columnId": "todo",
    "title": "Wire OAuth callback",
    "description": "PKCE flow + token refresh.",
    "priority": "high",
    "assignee": "JD"
  },
  {
    "id": "j2",
    "columnId": "doing",
    "title": "Realtime cursor sync",
    "description": "Broadcast presence over WS.",
    "priority": "medium",
    "assignee": "MR"
  },
  {
    "id": "j3",
    "columnId": "done",
    "title": "Onboarding email v2",
    "description": "A/B test variant B.",
    "priority": "low"
  }
];

import { useCallback } from "react";
import type { KanbanCardData } from "./types";

/**
 * Called whenever a card is dropped into a new position via DnD.
 * Replace the body with your real backend call (e.g. fetch PATCH).
 */
export function useJsxCardDialogBoardCardChange() {
  return useCallback((event: {
    card: KanbanCardData;
    fromColumnId: string;
    toColumnId: string;
    fromIndex: number;
    toIndex: number;
    cards: KanbanCardData[];
  }) => {
    console.log("[kanban] card moved:", event);
  }, []);
}

export function useJsxCardDialogBoardLoadMore() {
  return useCallback(async (event: { columnId: string; cursor?: string }) => {
    console.log("[kanban] load more:", event);
  }, []);
}

/**
 * Re-export of the kanban engine types — imported by the generated component
 * so callers don't need to dig into the engine internals.
 */
export type {
  KanbanBuilderConfig,
  KanbanCardData,
  KanbanColumnConfig,
  KanbanCardField,
} from "../../components/kanban/types";
